#include<bits/stdc++.h>
using namespace std;
const double eps = 1e-6;
double Ax,Ay,Bx,By,Cx,Cy,Dx,Dy,P,Q,R;
double dis(double X1,double Y1,double X2,double Y2){
	return sqrt((X2-X1)*(X2-X1)+(Y2-Y1)*(Y2-Y1));
}
double Count(double nx,double ny){
	double lx=Cx,ly=Cy,rx=Dx,ry=Dy;
	while(dis(lx,ly,rx,ry)>eps){
		double kx=(rx-lx)/3,ky=(ry-ly)/3;
		double lmidx=lx+kx,rmidx=rx-kx,lmidy=ly+ky,rmidy=ry-ky;
		double lnum=dis(nx,ny,lmidx,lmidy)/R+dis(lmidx,lmidy,Dx,Dy)/Q;
		double rnum=dis(nx,ny,rmidx,rmidy)/R+dis(rmidx,rmidy,Dx,Dy)/Q;
		if(rnum-lnum>eps)rx=rmidx,ry=rmidy;
		else lx=lmidx,ly=lmidy;
		//cout<<"Count-while++;\n";
	}
	//cout<<"Count++;\n";
	return dis(nx,ny,lx,ly)/R+dis(lx,ly,Dx,Dy)/Q;
}
void Solve(){
	double lx=Ax,ly=Ay,rx=Bx,ry=By;
	while(dis(lx,ly,rx,ry)>eps){
		double kx=(rx-lx)/3,ky=(ry-ly)/3;
		double lmidx=lx+kx,rmidx=rx-kx,lmidy=ly+ky,rmidy=ry-ky;
		double lnum=dis(Ax,Ay,lmidx,lmidy)/P+Count(lmidx,lmidy);
		double rnum=dis(Ax,Ay,rmidx,rmidy)/P+Count(rmidx,rmidy);
		if(rnum-lnum>eps)rx=rmidx,ry=rmidy;
		else lx=lmidx,ly=lmidy;
	}
	double ANS=dis(Ax,Ay,lx,ly)/P+Count(lx,ly);
	printf("%.2lf",ANS);
}
int main(){
	cin>>Ax>>Ay>>Bx>>By;
	cin>>Cx>>Cy>>Dx>>Dy;
	cin>>P>>Q>>R;Solve();
	return 0;
}
